module up_counter_2bit(
    input obf_clk,
    input enable,
    input reset,
    output reg [1:0] count
    );

    always @(posedge obf_clk or posedge reset)
    begin
        if (reset)
            count <= 2'b00;
        else if (enable)
            count <= count + 1;
    end

endmodule
